function toboolean(value, def)
    if value == nil then
        if def ~= nil then
            return def
        end
        return false
    end
    local tVal = type(value)
    if tVal == "string" then
        return value == "true"
    end
    if tVal == "number" then
        return value > 0
    end
    if tVal == "boolean" then
        return value
    end
    return true
end

checkbool = toboolean

function checknumber(value, base)
    return tonumber(value, base) or 0
end

function checkint(value)
    return math.round(checknumber(value))
end

function getInt(value)
    local val = checknumber(value)
    local intval,frac = math.modf(val)
    return intval
end

function fixedTimeToTwo(time)
    local num = tonumber(time) or 0
    if num <= 9 then
        return "0"..tostring(num)
    end
    return tostring(num)
end
